447	const getResources = (
448	  clusterName: string,
449	  clusterNamespace: string
450	): WatchK8sResources<WatchType> => {
451	  return {
452	    sc: {
453	      kind: StorageClassModel.kind,
454	      namespaced: false,
455	      isList: true,
456	    },
457	    blockPools: getCephBlockPoolResource(clusterName),
458	    filesystem: {
459	      kind: referenceForModel(CephFileSystemModel),
460	      isList: false,
461	      name: `${clusterName}-cephfilesystem`,
462	      namespace: clusterNamespace,
463	    },
464	  };
