467	const StoragePoolListPage: React.FC = () => {
468	  const {
469	    odfNamespace: clusterNs,
470	    isODFNsLoaded,
471	    odfNsLoadError,
472	  } = useODFNamespaceSelector();
473	  const { systemFlags, areFlagsLoaded, flagsLoadError } =
474	    useODFSystemFlagsSelector();
475	  const clusterName = systemFlags[clusterNs]?.ocsClusterName;
476	
477	  const response = useK8sWatchResources(
478	    getResources(clusterName, clusterNs)
479	  ) as WatchK8sResults<WatchType>;
480	
481	  const storageClasses = response.sc.data;
482	  const scLoaded = response.sc.loaded;
483	  const scError = response.sc.loadError;
484	
485	  const blockPools = response.blockPools.data;
486	  const blockPoolsLoaded = response.blockPools.loaded;
487	  const blockPoolsError = response.blockPools.loadError;
488	
489	  const filesystem = response.filesystem.data;
490	  const filesystemLoaded = response.filesystem.loaded;
491	  const filesystemError = response.filesystem.loadError;
492	
493	  const memoizedSC: StorageClassResourceKind[] = useDeepCompareMemoize(
494	    storageClasses,
495	    true
496	  );
497	
498	  const poolsFromBlock = getStoragePoolsFromBlockPools(blockPools);
499	  const poolsFromFS = getStoragePoolsFromFilesystem(filesystem);
500	  const storagePools =
501	    poolsFromBlock && poolsFromFS ? poolsFromBlock.concat(poolsFromFS) : [];
502	
503	  const loaded =
504	    blockPoolsLoaded &&
505	    filesystemLoaded &&
506	    isODFNsLoaded &&
507	    (areFlagsLoaded || scLoaded);
508	
509	  const error =
510	    odfNsLoadError ||
511	    flagsLoadError ||
512	    scError ||
513	    blockPoolsError ||
514	    filesystemError;
515	
516	  return (
517	    <StoragePoolList
518	      storagePools={storagePools}
519	      storageClasses={memoizedSC}
520	      loaded={loaded}
521	      loadError={error}
522	      clusterName={clusterName}
523	    />
524	  );
525	};
