535	const StoragePoolList: React.FC<StoragePoolListProps> = ({
536	  storagePools,
537	  storageClasses,
538	  loaded,
539	  loadError,
540	  clusterName,
541	}) => {
542	  const { t } = useCustomTranslation();
543	
544	  const location = useLocation();
545	  const listPagePath: string = location.pathname;
