547	  const poolNames = storagePools.map((pool) => pool.metadata?.name);
548	
549	  // Todo: fix these metrics they are giving duplicate errors
550	  const [poolRawCapacityMetrics, rawCapLoadError, rawCapLoading] =
551	    useCustomPrometheusPoll(
552	      getValidPrometheusPollObj(
553	        {
554	          endpoint: 'api/v1/query' as any,
555	          query: getPoolQuery(
556	            poolNames,
557	            StorageDashboardQuery.POOL_RAW_CAPACITY_USED,
558	            clusterName
559	          ),
560	          basePath: usePrometheusBasePath(),
561	        },
562	        !!poolNames?.length
563	      )
564	    );
565	
566	  const [maxAvailableCapacityData, maxAvailableLoadError, maxAvailableLoading] =
567	    useCustomPrometheusPoll(
568	      getValidPrometheusPollObj(
569	        {
570	          endpoint: 'api/v1/query' as any,
571	          query: getPoolQuery(
572	            poolNames,
573	            StorageDashboardQuery.POOL_MAX_CAPACITY_AVAILABLE,
574	            clusterName
575	          ),
576	          basePath: usePrometheusBasePath(),
577	        },
578	        !!poolNames?.length
579	      )
580	    );
581	
582	  const [
583	    poolUtilizationData,
584	    poolUtilizationLoadError,
585	    poolUtilizationLoading,
586	  ] = useCustomPrometheusPoll(
587	    getValidPrometheusPollObj(
588	      {
589	        endpoint: 'api/v1/query' as any,
590	        query: getPoolQuery(
591	          poolNames,
592	          StorageDashboardQuery.POOL_UTILIZATION_PERCENTAGE,
593	          clusterName
594	        ),
595	        basePath: usePrometheusBasePath(),
596	      },
597	      !!poolNames?.length
598	    )
599	  );
600	
601	  const [compressionSavings, compressionLoadError, compressionLoading] =
602	    useCustomPrometheusPoll(
603	      getValidPrometheusPollObj(
604	        {
605	          endpoint: 'api/v1/query' as any,
606	          query: getPoolQuery(
607	            poolNames,
608	            StorageDashboardQuery.POOL_COMPRESSION_SAVINGS,
609	            clusterName
610	          ),
611	          basePath: usePrometheusBasePath(),
612	        },
613	        !!poolNames?.length
614	      )
615	    );
616	
617	  const customData = React.useMemo(() => {
618	    const poolRawCapacity: PoolMetrics = getPerPoolMetrics(
619	      poolRawCapacityMetrics,
620	      rawCapLoadError,
621	      rawCapLoading
622	    );
623	    const poolMaxAvailableCapacity: PoolMetrics = getPerPoolMetrics(
624	      maxAvailableCapacityData,
625	      maxAvailableLoadError,
626	      maxAvailableLoading
627	    );
628	    const poolUtilization: PoolMetrics = getPerPoolMetrics(
629	      poolUtilizationData,
630	      poolUtilizationLoadError,
631	      poolUtilizationLoading
632	    );
633	    const poolCompressionSavings: PoolMetrics = getPerPoolMetrics(
634	      compressionSavings,
635	      compressionLoadError,
636	      compressionLoading
637	    );
638	
639	    return {
640	      storageClasses: storageClasses ?? [],
641	      poolRawCapacity,
642	      poolMaxAvailableCapacity,
643	      poolUtilization,
644	      poolCompressionSavings,
645	
646	      listPagePath,
647	    };
648	  }, [
649	    storageClasses,
650	    listPagePath,
651	    poolRawCapacityMetrics,
652	    rawCapLoadError,
653	    rawCapLoading,
654	    maxAvailableCapacityData,
655	    maxAvailableLoadError,
656	    maxAvailableLoading,
657	    poolUtilizationData,
658	    poolUtilizationLoadError,
659	    poolUtilizationLoading,
660	    compressionSavings,
661	    compressionLoadError,
662	    compressionLoading,
663	  ]);
664	
665	  const [data, filteredData, onFilterChange] = useListPageFilter(storagePools);
666	  const createPath = `/odf/system/ns/${getNamespace(data[0])}/ocs.openshift.io~v1~StorageCluster/${clusterName}/storage-pools/create/~new`;
667	
668	  return (
669	    <>
670	      <ListPageHeader title={t('Storage pools')}>
671	        {loaded && (
672	          <ListPageCreateLink to={createPath} data-test="item-create">
673	            {t('Create storage pool')}
674	          </ListPageCreateLink>
675	        )}
676	      </ListPageHeader>
677	      <ListPageBody>
678	        <ListPageFilter
679	          data={data}
