682	          hideColumnManagement={true}
683	        />
684	        <StoragePoolListTable
685	          data={filteredData}
686	          unfilteredData={data}
687	          loaded={loaded}
688	          loadError={loadError}
689	          rowData={{ ...customData }}
690	        />
691	      </ListPageBody>
692	    </>
693	  );
694	};
